GunTab:AddDropdown(
    {
        Name = "Give Gun",
        Default = "",
        Options = {"Remington 870", "AK-47", "M9", "M4AI", "Riot Sheild"},
        Callback = function(v)
            plr = LocalPlayer
            local currentCframe = LocalPlayer.Character.HumanoidRootPart.CFrame

            function unsit()
                plr.Character:FindFirstChildOfClass("Humanoid").Sit = false
            end

            function MoveTo(Pos, t)
                unsit()
                pcall(
                    function()
                        if typeof(Pos):lower() == "position" then
                            Pos = CFrame.new(Pos)
                        end
                        for i = 1, 3 do
                            plr.Character:FindFirstChild("HumanoidRootPart").CFrame = Pos
                        end
                    end
                )
            end

            function GetGun(Item, Ignore)
                local saved = LocalPlayer.Character:GetPrimaryPartCFrame()
                print(saved)
                if
                    workspace.Prison_ITEMS.giver:FindFirstChild(Item) and
                        workspace.Prison_ITEMS.giver:FindFirstChild(Item):FindFirstChild("ITEMPICKUP")
                 then
                    Item = workspace.Prison_ITEMS.giver:FindFirstChild(Item)
                    local ohInstance1 = Item:FindFirstChildOfClass("Part")
                    MoveTo(CFrame.new(ohInstance1.Position))
                    repeat
                        task.wait()
                        local ohInstance1 = Item:FindFirstChildOfClass("Part")
                        MoveTo(CFrame.new(ohInstance1.Position))
                        task.spawn(
                            function()
                                workspace.Remote.ItemHandler:InvokeServer(ohInstance1)
                            end
                        )
                        task.wait()
                    until plr.Backpack:FindFirstChild(Item.Name) or plr.Character:FindFirstChild(Item.Name)
                end
                if Ignore ~= true then
                    plr.Character:SetPrimaryPartCFrame(Ignore or saved)
                end
            end

            GetGun(v, true)
            task.wait(.25)
            LocalPlayer.Character.HumanoidRootPart.CFrame = currentCframe
        end
    }
)

GunTab:AddDropdown(
    {
        Name = "Give Item",
        Default = "",
        Options = {"Key card", "Crude Knife", "Hammer"},
        Callback = function(v)
            plr = LocalPlayer
            local currentCframe = LocalPlayer.Character.HumanoidRootPart.CFrame

            function unsit()
                plr.Character:FindFirstChildOfClass("Humanoid").Sit = false
            end

            function MoveTo(Pos, t)
                unsit()
                pcall(
                    function()
                        if typeof(Pos):lower() == "position" then
                            Pos = CFrame.new(Pos)
                        end
                        for i = 1, 3 do
                            plr.Character:FindFirstChild("HumanoidRootPart").CFrame = Pos
                        end
                    end
                )
            end

            function GetItem(Item, Ignore)
                local saved = LocalPlayer.Character:GetPrimaryPartCFrame()
                if
                    workspace.Prison_ITEMS.single:FindFirstChild(Item) and
                        workspace.Prison_ITEMS.single:FindFirstChild(Item):FindFirstChild("ITEMPICKUP")
                 then
                    Item = workspace.Prison_ITEMS.single:FindFirstChild(Item)
                    local ohInstance1 =
                        Item:FindFirstChildOfClass("Part") or Item:FindFirstChildOfClass("UnionOperation")
                    MoveTo(CFrame.new(ohInstance1.Position))
                    repeat
                        task.wait()
                        local ohInstance1 =
                            Item:FindFirstChildOfClass("Part") or Item:FindFirstChildOfClass("UnionOperation")
                        MoveTo(CFrame.new(ohInstance1.Position))
                        task.spawn(
                            function()
                                workspace.Remote.ItemHandler:InvokeServer(ohInstance1)
                            end
                        )
                        task.wait()
                    until plr.Backpack:FindFirstChild(Item.Name) or plr.Character:FindFirstChild(Item.Name)
                end
                if Ignore ~= true then
                    plr.Character:SetPrimaryPartCFrame(Ignore or saved)
                end
            end

            GetItem(v, true)
            task.wait(.25)
            LocalPlayer.Character.HumanoidRootPart.CFrame = currentCframe
        end
    }
)

